mapper.select:
/* ====== secu.securityMgmt.stopUserList =========*/
SELECT CUM.ORGN_ID AS ORGN_ID , (SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = CUM.ORGN_ID AND ROWNUM = 1) AS ORGN_NM , CUM.USR_ID AS USR_ID , CUM.USR_NM AS USR_NM , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0003' AND CD_VAL = CUM.ATTC_SCTN_CD) AS ATTC_SCTN_NM , TO_CHAR(CUM.RVISN_DTTM, 'YYYY.MM.DD HH24:MI:SS') AS RVISN_DTTM , TO_CHAR(CUM.REGST_DTTM, 'YYYY.MM.DD HH24:MI:SS') AS REGST_DTTM , TO_CHAR(CUM.LAST_LOGIN_DT, 'YYYY.MM.DD HH24:MI:SS') AS LAST_LOGIN_DT FROM CMN_USR_MST CUM WHERE TO_CHAR(RVISN_DTTM, 'YYYYMMDD') BETWEEN #{searchStrtDt, jdbcType=VARCHAR} AND #{searchEndDt, jdbcType=VARCHAR}
UNION ALL
SELECT CUM.ORGN_ID AS ORGN_ID , (SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = CUM.ORGN_ID AND ROWNUM = 1) AS ORGN_NM , CUM.USR_ID AS USR_ID , CUM.USR_NM AS USR_NM , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0003' AND CD_VAL = CUM.ATTC_SCTN_CD) AS ATTC_SCTN_NM , TO_CHAR(CUM.RVISN_DTTM, 'YYYY.MM.DD HH24:MI:SS') AS RVISN_DTTM , TO_CHAR(CUM.REGST_DTTM, 'YYYY.MM.DD HH24:MI:SS') AS REGST_DTTM , TO_CHAR(CUM.LAST_LOGIN_DT, 'YYYY.MM.DD HH24:MI:SS') AS LAST_LOGIN_DT FROM CMN_USR_MST CUM WHERE USG_YN = 'S'

