SELECT CUM.ORGN_ID AS orgnId , (SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = CUM.ORGN_ID AND ROWNUM = 1) AS orgnNm , CUM.USR_ID AS usrId , CUM.USR_NM AS usrNm , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0003' AND CD_VAL = CUM.ATTC_SCTN_CD) AS attcSctnNm , TO_CHAR(CUM.RVISN_DTTM, 'YYYY.MM.DD HH24:MI:SS') AS rvisnDttm , TO_CHAR(CUM.REGST_DTTM, 'YYYY.MM.DD HH24:MI:SS') AS regstDttm , TO_CHAR(CUM.LAST_LOGIN_DT, 'YYYY.MM.DD HH24:MI:SS') AS lastLoginDt FROM CMN_USR_MST CUM WHERE USG_YN = 'S'
